<pre class="wp-block-code"><code lang="cpp" class="language-cpp">#include &lt;bits/stdc++.h&gt;

using namespace std;

class Solution {
  void findTopoSort(int node, vector &lt; int &gt; &amp; vis, stack &lt; int &gt; &amp; st, vector &lt; int &gt; adj[]) {
    vis[node] = 1;

    for (auto it: adj[node]) {
      if (!vis[it]) {
        findTopoSort(it, vis, st, adj);
      }
    }
    st.push(node);
  }
  public:
    vector &lt; int &gt; topoSort(int N, vector &lt; int &gt; adj[]) {
      stack &lt; int &gt; st;
      vector &lt; int &gt; vis(N, 0);
      for (int i = 0; i &lt; N; i++) {
        if (vis[i] == 0) {
          findTopoSort(i, vis, st, adj);
        }
      }
      vector &lt; int &gt; topo;
      while (!st.empty()) {
        topo.push_back(st.top());
        st.pop();
      }
      return topo;

    }
};

// { Driver Code Starts.
int main() {

  int N = 6;

  vector &lt; int &gt; adj[5 + 1];

  adj[5].push_back(2);
  adj[5].push_back(0);
  adj[4].push_back(0);
  adj[4].push_back(1);
  adj[2].push_back(3);
  adj[3].push_back(1);

  Solution obj;
  vector &lt; int &gt; res = obj.topoSort(6, adj);

  cout &lt;&lt; "Toposort of the given graph is:" &lt;&lt; endl;
  for (int i = 0; i &lt; res.size(); i++) {
    cout &lt;&lt; res[i] &lt;&lt; " ";
  }

  return 0;
} 
